import React from 'react';
import { FaTachometerAlt, FaUniversity, FaSignOutAlt } from 'react-icons/fa'; // Modern icons
import { CNavItem } from '@coreui/react';

const createNavItem = (name, to, icon) => ({
  component: CNavItem,
  name,
  to,
  icon: <icon className="nav-icon" />, // Directly using icon as a component
});

const menuList = [
  createNavItem('Dashboard', '/dashboard', FaTachometerAlt),
  createNavItem('Colleges', '/colleges', FaUniversity),
  createNavItem('Logout', '/logout', FaSignOutAlt),
];

export default menuList;
